// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---------------------------------------------------------

/**
 * Encode a compound cursor (created_at, id) as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // Use ISO string so the timestamp survives JSON round-tripping precisely.
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into { created_at, id }.
 * Throws on anything malformed so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('INVALID_CURSOR');
    }

    if (
        !decoded ||
        typeof decoded !== 'object' ||
        typeof decoded.id === 'undefined' ||
        typeof decoded.created_at === 'undefined'
    ) {
        throw new Error('INVALID_CURSOR');
    }

    // Validate the timestamp is parseable.
    const ts = new Date(decoded.created_at);
    if (isNaN(ts.getTime())) {
        throw new Error('INVALID_CURSOR');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

// --- Endpoint ---------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    const { after } = req.query;

    let cursor = null;
    if (after) {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }
    }

    // Fetch limit + 1 rows to detect whether another page exists.
    const fetchCount = limit + 1;

    let result;
    if (cursor) {
        // Sort is (created_at DESC, id DESC), so "next page" rows are those
        // strictly *less than* the cursor in that same ordering.
        // The row-value comparison (created_at, id) < (cursorCreatedAt, cursorId)
        // expresses the compound keyset condition cleanly and uses the index.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, fetchCount]
        );
    } else {
        // First page: no cursor filter.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [fetchCount]
        );
    }

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

### Note on the `(created_at, id) < ($1, $2)` comparison

PostgreSQL supports **row-value comparisons**, so `(created_at, id) < ($1, $2)` evaluates exactly as the lexicographic keyset condition:

```
created_at < $1 OR (created_at = $1 AND id < $2)
```

It's correct for the `ORDER BY created_at DESC, id DESC` ordering and lets a composite index on `(created_at DESC, id DESC)` (or even the default ordering) be used directly. If you'd rather not rely on row-value syntax, the expanded `OR` form above is equivalent.

> Index tip: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` makes both the first-page and keyset queries index-only seeks.

### Why cursor-based pagination is superior here

1. **Constant-time deep pages.** `OFFSET N` forces Postgres to scan and discard the first *N* matching rows on every request. At page 5,000 that's hundreds of thousands of rows thrown away per query. A keyset `WHERE (created_at, id) < (...)` seeks straight to the starting point via the index — page 5,000 costs the same as page 1.

2. **No expensive COUNT.** `SELECT COUNT(*)` on a large table is a full scan (or index scan) every request. Cursor pagination doesn't need a total to compute "next," so it's removed entirely.

3. **Stable results under concurrent writes.** With OFFSET, a post inserted or deleted between requests shifts every subsequent row, causing items to be skipped or shown twice across pages. A cursor anchors to a specific `(created_at, id)` position, so newly inserted rows don't corrupt the user's scroll through the feed.

4. **Opaque, tamper-resistant cursors.** Encoding `(created_at, id)` as base64 JSON keeps the client from depending on internal column semantics — you can change the underlying sort key later without breaking clients, and clients can't fabricate arbitrary offsets.

The main trade-off: you lose random access to an arbitrary page number and an exact total count. For an infinite-scroll / "load more" feed (the typical use for `created_at DESC`), that's exactly the right trade.

