/**
 * Encode a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * `created_at` is serialised as an ISO-8601 string so PostgreSQL can compare it
 * directly against the timestamp column without any extra casting.
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload).toString('base64url'); // URL-safe, no padding issues
}

/**
 * Decode a cursor string.  Returns { created_at, id } on success, or null when
 * the string is missing, not valid base64, not valid JSON, or is missing the
 * required fields — callers must treat null as a 400 Bad Request.
 */
function decodeCursor(cursorStr) {
    if (!cursorStr) return null;
    try {
        const payload = JSON.parse(Buffer.from(cursorStr, 'base64url').toString('utf8'));

        if (
            typeof payload !== 'object' ||
            payload === null ||
            typeof payload.created_at === 'undefined' ||
            payload.created_at === null ||
            typeof payload.id === 'undefined' ||
            payload.id === null
        ) {
            return null; // structurally valid JSON but wrong shape
        }

        return { created_at: payload.created_at, id: payload.id };
    } catch {
        return null; // not base64, not JSON, etc.
    }
}

// ─── Endpoint ──────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ─────────────────────────────────────────────
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after;

    let cursor = null;
    if (afterParam !== undefined) {          // parameter present but may be empty
        cursor = decodeCursor(afterParam);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── 2. Query — LIMIT N+1 trick, no COUNT, no OFFSET ───────────────────────
    //
    // Compound cursor condition for ORDER BY created_at DESC, id DESC:
    //
    //   The next page consists of rows that sort *after* the cursor row, i.e.
    //   rows with a strictly smaller created_at, OR the same created_at with a
    //   strictly smaller id (because id is the tie-breaker in DESC order).
    //
    //   (created_at < $cursor_ts)
    //     OR (created_at = $cursor_ts AND id < $cursor_id)
    //
    // Fetching limit+1 rows lets us detect whether another page exists without
    // an expensive COUNT(*) scan.

    let rows;
    if (cursor) {
        const result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                      created_at < $1
                      OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
        rows = result.rows;
    } else {
        // First page — no cursor filter
        const result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
        rows = result.rows;
    }

    // ── 3. Detect next page & build response ───────────────────────────────────
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows; // drop the sentinel row

    // Cursor points at the LAST row we're actually returning, not the sentinel.
    const lastPost   = posts.length > 0 ? posts[posts.length - 1] : null;
    const nextCursor = hasMore && lastPost
        ? encodeCursor(lastPost.created_at, lastPost.id)
        : null;

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when this is the last page
            limit,
        },
    });
}
```

---

### Recommended index

The compound cursor WHERE clause is only fast if PostgreSQL can use an index. Add:

```sql
CREATE INDEX CONCURRENTLY idx_posts_published_cursor
    ON posts (published, created_at DESC, id DESC)
    WHERE published = true;   -- partial index keeps it small
```

With this index the query is `O(log n + limit)` regardless of how many rows are in the table.

---

### Why cursor-based is better here

| Problem | Offset | Cursor |
|---|---|---|
| **Skipped / duplicate rows** | A new post inserted between two page fetches shifts all offsets, so page 2 repeats the last row of page 1. | The WHERE anchor is tied to a specific row's values, so inserts and deletes elsewhere don't affect results. |
| **Performance at scale** | `OFFSET 50000` tells PostgreSQL to read and discard 50 000 rows before returning anything — cost grows linearly with depth. | The WHERE clause on an indexed column gives the storage engine a precise starting point; cost is roughly constant regardless of depth. |
| **Expensive total count** | Callers need `COUNT(*)` to know `totalPages`, which is a full sequential scan on large tables. | `hasMore` is derived for free from the N+1 trick — no COUNT needed. |
| **Consistency** | Page numbers are meaningless if rows change between requests. | The cursor is a stable bookmark into an ordered stream. |

The trade-off is that random access ("jump to page 47") is not possible, which is acceptable here because the use case is sequential feed / infinite-scroll consumption rather than arbitrary navigation.

